import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.Dj2sMFyx.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Kandelo","text":"A browser computer for real software","tagline":"Boot a VFS image and run shells, server software, command-line tools, and graphical experiments in a browser tab.","actions":[{"theme":"brand","text":"Open Kandelo","link":"https://automattic.github.io/kandelo/"},{"theme":"alt","text":"Use the Browser UI","link":"/guide/current-ui"},{"theme":"alt","text":"Build a Browser App","link":"/guide/browser-apps"}]},"features":[{"title":"VFS images are the machine","details":"A VFS image carries the programs, files, configs, and metadata Kandelo needs to boot a browser machine quickly."},{"title":"More than one process","details":"Kandelo can run shells, command-line tools, web servers, databases, and early framebuffer/audio demos as cooperating Wasm processes."},{"title":"Bring your own software","details":"Build VFS images and publish them through direct links or package-source gallery manifests."}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1784914006000}'),i={name:"index.md"};function s(l,e,n,d,c,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<div class="warning custom-block"><p class="custom-block-title">API stability</p><p>Kandelo&#39;s browser host, VFS image tooling, package-source workflow, and demo metadata are experimental. Public shapes can change at any time. Pin the Kandelo commit or package version you build against, and expect to update your integration as the project evolves.</p></div><h2 id="what-this-site-covers" tabindex="-1">What This Site Covers <a class="header-anchor" href="#what-this-site-covers" aria-label="Permalink to &quot;What This Site Covers&quot;">​</a></h2><p>Use these docs if you want to:</p><ul><li>boot and share machines in the current Kandelo browser UI;</li><li>host a <code>.vfs</code> or <code>.vfs.zst</code> image and open it through Kandelo;</li><li>build a custom browser app that starts Kandelo directly;</li><li>create, inspect, modify, and publish VFS images;</li><li>publish a gallery source that appears in the Kandelo UI.</li></ul><h2 id="the-dream" tabindex="-1">The Dream <a class="header-anchor" href="#the-dream" aria-label="Permalink to &quot;The Dream&quot;">​</a></h2><p>The dream is still to &quot;fold a computer into a URL&quot;: a link should be able to identify a VFS image, verify the software it references, choose a boot command, and carry small bits of user state. Serious systems will keep large artifacts as signed, cacheable downloads, but the URL should be enough to tell Kandelo what to boot.</p><p>For lower-level implementation details, keep using the repository docs:</p><ul><li><a href="https://github.com/Automattic/kandelo/blob/main/docs/architecture.md" target="_blank" rel="noreferrer">Architecture</a></li><li><a href="https://github.com/Automattic/kandelo/blob/main/docs/browser-support.md" target="_blank" rel="noreferrer">Browser support</a></li><li><a href="https://github.com/Automattic/kandelo/blob/main/docs/porting-guide.md" target="_blank" rel="noreferrer">Porting guide</a></li><li><a href="https://github.com/Automattic/kandelo/blob/main/docs/package-sources.md" target="_blank" rel="noreferrer">Package sources</a></li><li><a href="https://github.com/Automattic/kandelo/blob/main/docs/package-management.md" target="_blank" rel="noreferrer">Package management</a></li></ul>',8)])])}const p=a(i,[["render",s]]);export{u as __pageData,p as default};
